changeSet.sql:
ALTER TABLE system_requirement_control_test_results ADD COLUMN document_id integer DEFAULT NULL;

ALTER TABLE system_requirement_control_test_results
	ADD CONSTRAINT fk_sys_ctrl_test_results_document FOREIGN KEY (document_id) REFERENCES documents (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE;

CREATE INDEX i_sys_ctrl_test_results_document ON system_requirement_control_test_results (document_id);

ALTER TABLE organization_requirement_control_test_results ADD COLUMN document_id integer DEFAULT NULL;

ALTER TABLE organization_requirement_control_test_results
	ADD CONSTRAINT fk_org_ctrl_test_results_document FOREIGN KEY (document_id) REFERENCES documents (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE;

CREATE INDEX i_org_ctrl_test_results_document ON organization_requirement_control_test_results (document_id);

rollback.sql:
ALTER TABLE system_requirement_control_test_results DROP COLUMN IF EXISTS document_id;
ALTER TABLE system_requirement_control_test_results DROP CONSTRAINT IF EXISTS fk_sys_ctrl_test_results_document;

ALTER TABLE organization_requirement_control_test_results DROP COLUMN IF EXISTS document_id;
ALTER TABLE organization_requirement_control_test_results DROP CONSTRAINT IF EXISTS fk_org_ctrl_test_results_document;
